class Solution {
    public int palindromePartition(String s, int k) {
        int n = s.length();
        int[][] dp = new int[n + 1][n + 1];
        for (int i = 1; i <= n; i++) {
            dp[i][i] = 0;
            for (int j = i - 1; j >= 1; j--) {
                dp[j][i] = dp[j + 1][i] + (s.charAt(j - 1) == s.charAt(i - 1) ? 0 : 1);
            }
        }
        int[][] dp2 = new int[n + 1][k + 1];
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= Math.min(i, k); j++) {
                for (int l = 1; l <= i - j; l++) {
                    dp2[i][j] = Math.min(dp2[i][j], dp2[l - 1][j - 1] + dp[l][i]);
                }
            }
        }
        return dp2[n][k];
    }
}
